import{_ as e,o as t,c as s,a5 as l}from"./chunks/framework.B5tqjWbr.js";const m=JSON.parse('{"title":"概念：两电平 SVPWM","description":"","frontmatter":{"date":"2026-06-22T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：两电平 SVPWM","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0040-two-level-svpwm.html` 的源稿。"},"headers":[],"relativePath":"content/power/concepts/two-level-svpwm.md","filePath":"content/power/concepts/two-level-svpwm.md","lastUpdated":null}'),o={name:"content/power/concepts/two-level-svpwm.md"};function n(i,a,r,p,c,d){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-两电平-svpwm" tabindex="-1">概念：两电平 SVPWM <a class="header-anchor" href="#概念-两电平-svpwm" aria-label="Permalink to &quot;概念：两电平 SVPWM&quot;">​</a></h1><p>本页是 <code>lessons/0040-two-level-svpwm.html</code> 的源稿。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>空间矢量脉宽调制（space vector pulse-width modulation / SVPWM）用相邻有效矢量和零矢量在一个 PWM 周期内平均合成目标 alpha/beta 电压。</p><h2 id="为什么-ups-pcs-需要它" tabindex="-1">为什么 UPS/PCS 需要它 <a class="header-anchor" href="#为什么-ups-pcs-需要它" aria-label="Permalink to &quot;为什么 UPS/PCS 需要它&quot;">​</a></h2><p>三相逆变器、三相有源整流器和 PCS 都要把 dq 控制器输出的电压参考转换为三相占空比。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sector = angle(v_alpha, v_beta)</span></span>
<span class="line"><span>T1, T2 = adjacent_vector_times(v_alpha, v_beta, Vdc, Ts)</span></span>
<span class="line"><span>T0 = Ts - T1 - T2</span></span></code></pre></div><h2 id="一个仿真任务" tabindex="-1">一个仿真任务 <a class="header-anchor" href="#一个仿真任务" aria-label="Permalink to &quot;一个仿真任务&quot;">​</a></h2><p>扫描调制比，画出三相占空比和六扇区轨迹。</p><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能列出 6 个有效矢量和 2 个零矢量。</li><li>能解释 T1、T2、T0。</li><li>能说明 min-max 注入与零序注入的关系。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><p>项目代码使用扇区法、min-max 法还是查表法？只确认阅读入口。</p>`,14)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
